281→            .maybeSingle();
282→
283→        if(!errorOriginal && originalJournal){
284→            ultimateSourceId = originalJournal.id;
285→            ultimateSourceUserId = originalJournal.user_id;
286→            ultimateSourceTitle = originalJournal.title;
