292→        .from('journals')
293→        .select('id')
294→        .eq('user_id', userId)
295→        .eq('repost_source_journal_id', ultimateSourceId)
296→        .eq('is_repost', true)
297→        .maybeSingle();
298→
299→    if(errorExisting){
300→        console.error('supabase error while checking existing repost:', errorExisting.message);
301→        throw {status: 500, error: 'supabase error while checking existing repost'};
302→    }
303→
304→    if(existingRepost){
305→        throw {status: 409, error: 'you have already reposted this post'};
306→    }
307→
308→    const repostTitle = `Repost: ${ultimateSourceTitle || 'Untitled'}`;
309→
310→    const {data: insertedRepost, error: errorInsertRepost} = await supabase
311→        .from('journals')
312→        .insert({
313→            user_id: userId,
314→            is_repost: true,
315→            repost_source_journal_id: ultimateSourceId,
316→            repost_caption: caption || null,
